from web3 import Web3

# Connect to Ethereum node
w3 = Web3(Web3.HTTPProvider('your_ethereum_node_url'))

def authenticate(signed_message):
    # Extract signature and message from signed message
    signature = signed_message['signature']
    message = signed_message['message']

    # Recover address from signature and message
    address = w3.eth.account.recover_message(message.encode('utf-8'), signature)

    # Return authenticated address
    return address